function safeStr(v) { return v === null || v === undefined ? '' : String(v).trim(); }
const items = $input.all();
return items.filter(item => {
  const j = item.json || {};
  if (safeStr(j.sharepicNeedStage) !== 'topic_ok') return false;
  const hcs = safeStr(j.headlineChoiceStage);
  if (hcs && hcs !== 'needs_kernbotschaft') return false;
  if (!safeStr(j.vorgangKey)) return false;
  return true;
});

function parseDate(v) { if (!v) return 0; const t = Date.parse(String(v)); return Number.isFinite(t) ? t : 0; }
const items = $input.all();
items.sort((a, b) => parseDate((a.json||{}).firstseen) - parseDate((b.json||{}).firstseen));
return items;

function safeStr(v) { return v === null || v === undefined ? '' : String(v).trim(); }
function parseObj(v) {
  if (!v) return {};
  if (typeof v === 'object' && !Array.isArray(v)) return v;
  try { const p = JSON.parse(String(v)); return (p && typeof p === 'object' && !Array.isArray(p)) ? p : {}; }
  catch (e) { return {}; }
}

const fakten = parseObj($json.faktenAgentJson);

return {
  json: {
    vorgangKey: $json.vorgangKey,
    vorgangsnummer: safeStr(fakten.vorgangsnummer),
    sourceTopic: fakten.sourceTopic,
    sourceConflict: fakten.sourceConflict,
    requiredTerms: fakten.requiredTerms,
    requiredObjects: fakten.requiredObjects,
    requiredAction: fakten.requiredAction,
    affectedGroups: fakten.affectedGroups,
    concreteNumbers: fakten.concreteNumbers,
    responsibilities: fakten.responsibilities,
    documentType: fakten.documentType,
    quotesVerbatim: fakten.quotesVerbatim,
    sprengstoff: $json.sprengstoff
  }
};

function safeStr(v) { return v === null || v === undefined ? '' : String(v).trim(); }
function asArray(v) { return Array.isArray(v) ? v.filter(Boolean).map(safeStr) : []; }

const response = $json || {};
const original = $('Satire-Shadow: Baue Eingabe').itemMatching($itemIndex).json || {};
const hasVariants = Array.isArray(response.variants) && response.variants.length > 0;

const result = hasVariants ? response : {
  vorgangKey: safeStr(original.vorgangKey),
  vorgangsnummer: safeStr(original.vorgangsnummer),
  variants: [],
  parseError: true,
  callFailed: true
};

return {
  json: {
    vorgangKey: safeStr(original.vorgangKey) || safeStr(response.vorgangKey),
    vorgangsnummer: safeStr(original.vorgangsnummer),
    satireAgentJson: JSON.stringify(result),
    sourceTopic: safeStr(original.sourceTopic),
    requiredObjects: asArray(original.requiredObjects),
    requiredAction: safeStr(original.requiredAction),
    affectedGroups: asArray(original.affectedGroups)
  }
};

// Kernbotschaft-first Umbau 2026-07-19, erweitert 2026-07-20: Satire-Agent waehlt intern aus 3
// Kernbotschaft-Kandidaten die staerkste aus (siehe ALLRIS_Satire_Agent.json), liefert dann 1
// finale kernbotschaft + 5 Formulierungen DERSELBEN Aussage (nicht mehr unabhaengige
// Angriffswinkel auf Formulierungs-Ebene). Es gibt daher
// keinen "Auto-Select fuer Text mehr - Text (P4) wartet komplett auf die Matrix-Bestaetigung,
// siehe Verarbeite Eignungs-Entscheidung in P3d (contentStage='awaiting_kernbotschaft').
// Die Umfrage zeigt die kernbotschaft sichtbar ueber den Formulierungs-Kandidaten, kein
// "(passt zum veroeffentlichten Text)"-Hinweis mehr noetig, da noch nichts veroeffentlicht ist.
function safeStr(v) { return v === null || v === undefined ? '' : String(v).trim(); }
function parseObj(v) {
  if (!v) return {};
  if (typeof v === 'object' && !Array.isArray(v)) return v;
  try { const p = JSON.parse(String(v)); return (p && typeof p === 'object' && !Array.isArray(p)) ? p : {}; }
  catch (e) { return {}; }
}
function asArr(v) {
  if (Array.isArray(v)) return v.filter(Boolean).map(safeStr);
  if (typeof v === 'string' && v.trim()) { try { const p = JSON.parse(v); if (Array.isArray(p)) return p.filter(Boolean).map(safeStr); } catch (e) {} }
  return [];
}

const satire = parseObj($json.satireAgentJson);
const variants = Array.isArray(satire.variants) ? satire.variants : [];
const kernbotschaft = safeStr(satire.kernbotschaft);
const faktenBase = $('Loop Vorgaenge').itemMatching($itemIndex).json || {};
const vorgangKey = safeStr($json.vorgangKey);
const vorgangsnummer = safeStr($json.vorgangsnummer);
const title = safeStr(faktenBase.title);
const vnCode = vorgangsnummer.replace(/[^0-9A-Za-z]+/g, '-').replace(/^-+|-+$/g, '');

const candidates = variants.slice(0, 5).map((v, i) => ({
  code: (vnCode ? vnCode + '-' : '') + 'K' + (i + 1),
  imageHeadline: safeStr(v.imageHeadline),
  imageSubline: safeStr(v.imageSubline),
  satireBrief: safeStr(v.satireBrief),
  satireAngle: safeStr(v.satireAngle),
  satirePunchlines: asArr(v.satirePunchlines),
  satireTarget: safeStr(v.satireTarget),
  satireIntensity: Number(v.satireIntensity) || 0,
  satireDoNotClaim: asArr(v.satireDoNotClaim),
  satireSafetyNote: safeStr(v.satireSafetyNote)
})).filter(c => c.imageHeadline && c.imageSubline);

const postedAt = new Date().toISOString();
const visualJson = JSON.stringify({ kernbotschaft, headlineCandidates: candidates, candidatesPostedAt: postedAt });

let matrixMessage = '';
let txnId = '';
let shouldPost = candidates.length >= 2 && !!kernbotschaft;

if (shouldPost) {
  const lines = ['🎯 Kernbotschaft für ' + vorgangsnummer + ' – ' + title, '', kernbotschaft, '', '🎨 Formulierungen zur Auswahl:', ''];
  for (const c of candidates) {
    lines.push(c.code + ': ' + c.imageHeadline + ' – ' + c.imageSubline);
    if (c.satireBrief) lines.push('   ' + c.satireBrief);
  }
  lines.push('');
  const exampleCode = candidates[0].code;
  lines.push('Antworte mit dem gewünschten Code (z.B. "' + exampleCode + '"), um Text UND Bild freizugeben, oder mit "' + vnCode + '-X" für eine komplett neue Kernbotschaft. Vor deiner Antwort wird noch nichts veröffentlicht.');
  matrixMessage = lines.join('\n');
  txnId = 'satire_hdl_' + Date.now() + '_' + vorgangKey.replace(/[^a-zA-Z0-9]/g, '').substring(0, 10);
}

return {
  json: {
    vorgangKey,
    vorgangsnummer,
    kernbotschaft,
    visualJson,
    headlineChoiceStage: shouldPost ? 'awaiting_headline_choice' : 'satire_agent_failed',
    imageStage: 'not_started',
    shouldPost,
    matrixMessage,
    txnId,
    matrixSentOk: false,
    matrixSendError: ''
  }
};

// Stellt den Vorgangskontext nach dem Matrix-Versand wieder her (gleiches Muster wie
// 'Stelle Kontext nach Matrix wieder her' in P5) - der HTTP-Node ersetzt das Item-JSON
// durch die rohe Matrix-API-Antwort und wuerde sonst vorgangKey/satireBrief/visualJson usw. verlieren.
const response = $json || {};
const base = $('Satire-Ergebnis: Baue Text-Auswahl + Umfrage').itemMatching($itemIndex).json || {};

const hasError = !!(
  response.error ||
  response.errcode ||
  (response.statusCode && Number(response.statusCode) >= 400)
);
const eventId = response.event_id || response.eventId || '';

return {
  json: {
    ...base,
    matrixSentOk: !hasError && !!eventId,
    matrixSendError: hasError ? (response.error || response.errcode || 'Matrix-Versand fehlgeschlagen') : ''
  }
};

// Satire-Agent lieferte weniger als 2 verwertbare Varianten (Parse-Fehler oder AI-Call
// fehlgeschlagen) - keine Matrix-Umfrage moeglich, kein Bild-Kandidat verfuegbar.
// Ohne diese Meldung wuerde die Zeile mit visualStage='satire_agent_failed' unbemerkt
// liegen bleiben (P5 wartet auf 'headline_selected', das kommt nie). Gleiches
// Alarmierungs-Muster wie 'Baue QA-Block Nachricht'.
function safeStr(v) { return v === null || v === undefined ? '' : String(v).trim(); }

const j = $json;
return {
  json: {
    ...j,
    txnId: 'satire-fail-' + Date.now() + '-' + Math.random().toString(36).slice(2),
    summaryMessage: '⚠️ Satire-Agent fehlgeschlagen: Vorgang ' + safeStr(j.vorgangsnummer) + ' (' + safeStr(j.vorgangKey) + ')\n' +
      'Grund: weniger als 2 verwertbare Varianten (Parse-Fehler oder AI-Call fehlgeschlagen).\n' +
      'Kein Bildvorschlag moeglich. Bitte in der Data Table pruefen und ggf. contentStage/visualStage manuell zuruecksetzen, um einen erneuten Versuch auszuloesen.'
  }
};
